mapper.update:
UPDATE sys_notification_recipient
SET is_read = 1,
    read_time = #{readTime}
WHERE recipient_user_id = #{userId}
  AND notification_id = #{notificationId}
  AND (is_read IS NULL OR is_read = 0)

