mapper.select:
SELECT COUNT(1)
FROM sys_notification_recipient r
INNER JOIN sys_notification n ON n.id = r.notification_id
WHERE r.recipient_user_id = #{userId}
  AND (r.is_read IS NULL OR r.is_read = 0)


        AND (
        n.biz_type NOT IN

            #{bt}

        OR (
        UPPER(TRIM(COALESCE(n.event_type, ''))) = 'COMPLETED'
        AND UPPER(TRIM(n.biz_type)) = 'REPAIR'
        AND EXISTS (
        SELECT 1 FROM repair_order o
        WHERE o.id = n.biz_id AND IFNULL(o.deleted, 0) = 0 AND o.applicant_id = #{userId}
        )
        )
        OR (
        UPPER(TRIM(COALESCE(n.event_type, ''))) = 'COMPLETED'
        AND UPPER(TRIM(n.biz_type)) = 'PURCHASE'
        AND EXISTS (
        SELECT 1 FROM purchase_order o
        WHERE o.id = n.biz_id AND IFNULL(o.deleted, 0) = 0 AND o.applicant_id = #{userId}
        )
        )
        OR (
        UPPER(TRIM(COALESCE(n.event_type, ''))) = 'COMPLETED'
        AND UPPER(TRIM(n.biz_type)) = 'SUPPLIES_CLAIM'
        AND EXISTS (
        SELECT 1 FROM supply_claim_order o
        WHERE o.id = n.biz_id AND IFNULL(o.deleted, 0) = 0 AND o.user_id = #{userId}
        )
        )
        )


        AND (
        n.biz_type IS NULL OR TRIM(n.biz_type) = ''
        OR UPPER(TRIM(n.biz_type)) NOT IN ('REPAIR', 'PURCHASE', 'SUPPLIES_CLAIM')
        OR (
        UPPER(TRIM(n.biz_type)) = 'REPAIR'
        AND EXISTS (
        SELECT 1 FROM repair_order o
        WHERE o.id = n.biz_id AND IFNULL(o.deleted, 0) = 0 AND o.applicant_id = #{userId}
        )
        )
        OR (
        UPPER(TRIM(n.biz_type)) = 'PURCHASE'
        AND EXISTS (
        SELECT 1 FROM purchase_order o
        WHERE o.id = n.biz_id AND IFNULL(o.deleted, 0) = 0 AND o.applicant_id = #{userId}
        )
        )
        OR (
        UPPER(TRIM(n.biz_type)) = 'SUPPLIES_CLAIM'
        AND EXISTS (
        SELECT 1 FROM supply_claim_order o
        WHERE o.id = n.biz_id AND IFNULL(o.deleted, 0) = 0 AND o.user_id = #{userId}
        )
        )
        )

mapper.delete:
